import{_ as a,C as i,o as t,c as n,a2 as o,b as c,w as r,a as l,E as d,a3 as u}from"./chunks/framework._O8Cueap.js";const y=JSON.parse('{"title":"Copilot CLI Security","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/security-copilot-cli.md","filePath":"concepts/security-copilot-cli.md"}'),h={name:"concepts/security-copilot-cli.md"};function p(g,e,C,A,m,I){const s=i("Mermaid");return t(),n("div",null,[e[1]||(e[1]=o('<h1 id="copilot-cli-security" tabindex="-1">Copilot CLI Security <a class="header-anchor" href="#copilot-cli-security" aria-label="Permalink to &quot;Copilot CLI Security&quot;">​</a></h1><p>When using the GitHub Copilot CLI with MCP servers, your environment variables and secrets are generally protected through process isolation. However, there are specific configuration risks you should manage to ensure the LLM cannot &quot;see&quot; them.</p><p>For OAO&#39;s server-side credential injection approach, see <a href="/open-agent-orchestra/concepts/security.html">AI Security</a>.</p><h2 id="how-copilot-cli-handles-your-secrets" tabindex="-1">How Copilot CLI Handles Your Secrets <a class="header-anchor" href="#how-copilot-cli-handles-your-secrets" aria-label="Permalink to &quot;How Copilot CLI Handles Your Secrets&quot;">​</a></h2><p>When you configure an MCP server in the CLI (typically stored in <code>mcp-config.json</code>), the secrets you provide are handled as follows:</p><p><strong>Process Isolation</strong> — The Copilot CLI starts your MCP server as a local sub-process using the <code>env</code> object you define in your JSON. The LLM interacts with this sub-process through standardized tools and commands; it does <strong>not</strong> have direct access to the process&#39;s internal environment variables.</p><p><strong>Context Separation</strong> — The value of a secret (like an API token) is used by the MCP server to authenticate with external services. This value is <strong>not</strong> automatically sent into the LLM&#39;s &quot;chat context&quot; — unless your specific MCP tool is poorly written and explicitly returns the token in its text output.</p>',7)),(t(),c(u,null,{default:r(()=>[d(s,{id:"mermaid-21",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20subgraph%20%22Copilot%20CLI%20Process%22%0A%20%20%20%20%20%20%20%20LLM%5B%22LLM%20Context%3Cbr%2F%3E(no%20secret%20access)%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22MCP%20Sub-Process%22%0A%20%20%20%20%20%20%20%20ENV%5B%22env%3A%20%7B%20API_KEY%3A%20sk-...%20%7D%22%5D%0A%20%20%20%20%20%20%20%20TOOL%5B%22MCP%20Tool%20Handler%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22External%20Service%22%0A%20%20%20%20%20%20%20%20API%5B%22Third-Party%20API%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20LLM%20--%3E%7C%22tool%20call%20(params%20only)%22%7C%20TOOL%0A%20%20%20%20TOOL%20--%3E%7C%22uses%20env%20secretly%22%7C%20API%0A%20%20%20%20API%20--%3E%7C%22result%20(no%20secrets)%22%7C%20TOOL%0A%20%20%20%20TOOL%20--%3E%7C%22text%20result%20only%22%7C%20LLM%0A%0A%20%20%20%20ENV%20-.-%3E%7C%22injected%20at%20spawn%22%7C%20TOOL%0A%0A%20%20%20%20style%20LLM%20fill%3A%23e53935%2Ccolor%3A%23fff%0A%20%20%20%20style%20ENV%20fill%3A%234CAF50%2Ccolor%3A%23fff%0A"})]),fallback:r(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=o('<div class="mermaid-source" data-mermaid-source=""></div><h2 id="security-risks-how-to-avoid-them" tabindex="-1">Security Risks &amp; How to Avoid Them <a class="header-anchor" href="#security-risks-how-to-avoid-them" aria-label="Permalink to &quot;Security Risks &amp; How to Avoid Them&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk</th><th>Problem</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Hardcoded secrets in <code>mcp-config.json</code></strong></td><td>Anyone with access to your machine (or a backup of your home directory) can read raw tokens</td><td>Use shell variable expansion: <code>&quot;TOKEN&quot;: &quot;${MY_SECRET_ENV}&quot;</code>, or set the variable in your terminal before running the CLI</td></tr><tr><td><strong>Leaky MCP tool output</strong></td><td>A poorly written MCP tool might return the token in its text response, leaking it into the LLM context</td><td>Always sanitize tool outputs — never echo secrets back. Validate that tool responses contain only data, not credentials</td></tr><tr><td><strong>Prompt injection via tool results</strong></td><td>An attacker-controlled API response could trick the LLM into exfiltrating secrets</td><td>Treat all external tool results as untrusted. Use write-tool permission controls for destructive actions</td></tr><tr><td><strong>Config file in version control</strong></td><td>Committing <code>mcp-config.json</code> with secrets to Git</td><td>Add <code>mcp-config.json</code> to <code>.gitignore</code>. Use environment variable references instead of raw values</td></tr></tbody></table><h2 id="oao-s-enhanced-protection" tabindex="-1">OAO&#39;s Enhanced Protection <a class="header-anchor" href="#oao-s-enhanced-protection" aria-label="Permalink to &quot;OAO&#39;s Enhanced Protection&quot;">​</a></h2><p>OAO goes beyond Copilot CLI defaults by adding server-side credential injection:</p><table tabindex="0"><thead><tr><th>Copilot CLI (Default)</th><th>OAO Platform</th></tr></thead><tbody><tr><td>Secrets stored in local <code>mcp-config.json</code></td><td>Secrets stored AES-256-GCM encrypted in database</td></tr><tr><td>User manually manages env vars</td><td>3-tier scoped variable system (workspace → user → agent)</td></tr><tr><td>LLM could see secrets if MCP tool leaks them</td><td>Jinja2 templates render secrets server-side — agent never sees raw values</td></tr><tr><td>No audit trail</td><td>All credential access is logged and auditable</td></tr><tr><td>Single user</td><td>Multi-tenant workspace isolation</td></tr></tbody></table><h2 id="best-practices-for-copilot-cli-users" tabindex="-1">Best Practices for Copilot CLI Users <a class="header-anchor" href="#best-practices-for-copilot-cli-users" aria-label="Permalink to &quot;Best Practices for Copilot CLI Users&quot;">​</a></h2><ol><li><strong>Never hardcode secrets</strong> in <code>mcp-config.json</code> — use environment variable references (<code>&quot;TOKEN&quot;: &quot;${MY_SECRET_ENV}&quot;</code>)</li><li><strong>Add <code>mcp-config.json</code> to <code>.gitignore</code></strong> — prevent accidental commits</li><li><strong>Audit MCP tool outputs</strong> — ensure tools never echo credentials back in their text responses</li><li><strong>Use write-tool permissions</strong> — mark destructive MCP tools to require approval</li><li><strong>Treat external tool results as untrusted</strong> — guard against prompt injection via API responses</li></ol><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/open-agent-orchestra/concepts/security.html">AI Security</a> — OAO&#39;s zero credential exposure architecture</li><li><a href="/open-agent-orchestra/concepts/variables.html">Variables</a> — Manage credentials at all three tiers</li><li><a href="/open-agent-orchestra/concepts/agents.html">Agents</a> — Configure MCP JSON templates</li></ul>',10))])}const f=a(h,[["render",p]]);export{y as __pageData,f as default};
